              <div className="bg-slate-900 text-white p-10 flex justify-between items-center relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-10 opacity-10">
                    <UserIcon className="w-40 h-40" />
                 </div>
                 <div className="relative z-10">
                   <div className="flex items-center gap-4 mb-2">
                      <span className="px-3 py-1 bg-blue-600 text-[10px] font-black uppercase tracking-widest rounded-full">Patient Profile</span>
                      <span className="text-slate-400 text-xs font-bold">ID: {selectedPatient.id.slice(-6)}</span>
                   </div>
                   <h2 className="text-4xl font-black tracking-tight">{selectedPatient.name}</h2>
                   <p className="text-slate-400 font-bold mt-1 uppercase text-xs tracking-widest">{selectedPatient.age} Years Old • {selectedPatient.phone}</p>
                 </div>
                 <button onClick={() => setSelectedPatient(null)} className="relative z-10 p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition-all border border-white/10">
                   <X className="w-6 h-6" />
                 </button>
              </div>

              <div className="flex border-b border-slate-100 bg-white sticky top-0 z-10 p-2 gap-2">
                 <TabButton active={detailTab === 'info'} onClick={() => setDetailTab('info')} icon={<FileText className="w-4 h-4" />} label="Overview" />
                 <TabButton active={detailTab === 'history'} onClick={() => setDetailTab('history')} icon={<ClipboardList className="w-4 h-4" />} label="Diagnosis Log" />
                 <TabButton active={detailTab === 'prescription'} onClick={() => setDetailTab('prescription')} icon={<Pill className="w-4 h-4" />} label="Prescriptions" />
              </div>

              <div className="flex-1 overflow-y-auto p-10 bg-slate-50/50 no-scrollbar">
                 {detailTab === 'info' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                        <h3 className="text-xl font-black text-slate-900 mb-6 tracking-tight">Clinical Summary</h3>
                        <div className="space-y-6">
                          <DataRow label="Current Condition" value={selectedPatient.condition || 'None Recorded'} />
                          <DataRow label="Last Consultation" value={selectedPatient.lastVisit} />
                          <DataRow label="Registry Date" value="2024-11-20" />
                        </div>
                      </div>
                      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                        <h3 className="text-xl font-black text-slate-900 mb-6 tracking-tight">Contact Information</h3>
                        <div className="space-y-6">
                          <DataRow label="Primary Phone" value={selectedPatient.phone} />
                          <DataRow label="Emergency Link" value="Guardian (Not Set)" />
                          <DataRow label="Address" value="District 4, Mogadishu" />
                        </div>
                      </div>
                    </div>
                 )}

                 {detailTab === 'history' && (
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                      <div className="lg:col-span-1">
                        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 sticky top-0">
                          <h3 className="text-xl font-black text-slate-900 mb-6 tracking-tight">New Diagnosis</h3>
                          <form onSubmit={handleAddHistory} className="space-y-4">
                            <div className="space-y-1">
                               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Main Concern</label>
                               <input required value={diagnosis} onChange={e => setDiagnosis(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" placeholder="e.g. Acute Pulpitis" />
                            </div>
                            <div className="space-y-1">
                               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Treatment Performed</label>
                               <textarea required value={treatment} onChange={e => setTreatment(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm h-28 resize-none" placeholder="Procedures performed..." />
                            </div>
                            <div className="space-y-1">
                               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Clinical Notes</label>
                               <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm h-20 resize-none" placeholder="Optional notes..." />
                            </div>
                            <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black rounded-2xl uppercase tracking-widest text-[10px] shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all flex items-center justify-center gap-2">
                               <Save className="w-4 h-4" /> Commit Record
                            </button>
                          </form>
                        </div>
                      </div>
                      <div className="lg:col-span-2 space-y-6">
                        <h3 className="text-xl font-black text-slate-900 tracking-tight flex items-center gap-3"><Clock className="w-5 h-5 text-slate-400" /> Historical Log</h3>
                        {patientHistory.filter(h => h.patientId === selectedPatient.id).length === 0 ? (
                           <div className="py-20 text-center bg-white rounded-[2.5rem] border border-dashed border-slate-200">
                             <p className="text-slate-400 font-bold text-sm">No previous records for this patient.</p>
                           </div>
                        ) : (
                           patientHistory.filter(h => h.patientId === selectedPatient.id).map(history => (
                             <div key={history.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 group relative">
                               <div className="flex justify-between items-start mb-4">
                                  <div>
                                     <h4 className="text-lg font-black text-slate-900">{history.diagnosis}</h4>
                                     <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">{history.date}</span>
                                  </div>
                                  <span className="px-4 py-1.5 bg-slate-50 rounded-xl text-[10px] font-black text-slate-400 uppercase tracking-widest">Dr. {history.doctorName}</span>
                               </div>
                               <div className="space-y-4">
                                  <div>
                                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Treatment Outcome</p>
                                     <p className="text-sm font-bold text-slate-700 leading-relaxed">{history.treatment}</p>
                                  </div>
                                  {history.notes && (
                                     <div className="p-4 bg-blue-50/50 rounded-2xl border border-blue-100">
                                        <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-1">Observation</p>
                                        <p className="text-xs font-medium text-blue-900 italic">"{history.notes}"</p>
                                     </div>
                                  )}
                               </div>
                             </div>
                           ))
                        )}
                      </div>
                    </div>
                 )}

                 {detailTab === 'prescription' && (
                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                      {/* Prescription Builder */}
                      <div className="lg:col-span-5 space-y-8">
                        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                           <h3 className="text-xl font-black text-slate-900 mb-8 tracking-tight flex items-center gap-3">
                              <Plus className="w-6 h-6 text-blue-600" /> New Medical Order
                           </h3>
                           <div className="grid grid-cols-2 gap-4 mb-4">
                              <div className="col-span-2 space-y-1">
                                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Drug Name</label>
                                 <input placeholder="e.g. Amoxicillin" value={medName} onChange={e => setMedName(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                              </div>
                              <div className="space-y-1">
                                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Dosage</label>
                                 <input placeholder="e.g. 500mg" value={medDosage} onChange={e => setMedDosage(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                              </div>
                              <div className="space-y-1">
                                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Frequency</label>
                                 <input placeholder="e.g. 3x Daily" value={medFrequency} onChange={e => setMedFrequency(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                              </div>
                              <div className="col-span-2 space-y-1">
                                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Duration</label>
                                 <input placeholder="e.g. 7 Days" value={medDuration} onChange={e => setMedDuration(e.target.value)} className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold text-sm" />
                              </div>
                           </div>
                           <button onClick={addMedToPrescription} className="w-full py-4 bg-slate-100 text-slate-900 font-black uppercase tracking-widest text-[10px] rounded-2xl hover:bg-slate-200 transition-all border border-slate-200 flex items-center justify-center gap-2 mb-6">
                              <Plus className="w-4 h-4" /> Add to Prescription List
                           </button>

                           {currentMeds.length > 0 && (
                             <div className="space-y-3 mb-8">
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Items to Prescribe</p>
                                {currentMeds.map((m, idx) => (
                                   <div key={idx} className="flex items-center justify-between p-4 bg-blue-50/50 rounded-2xl border border-blue-100 group">
                                      <div>
                                         <p className="font-black text-slate-900 text-sm">{m.name}</p>
                                         <p className="text-[10px] font-bold text-blue-600 uppercase tracking-wider">{m.dosage} • {m.frequency} • {m.duration}</p>
                                      </div>
                                      <button onClick={() => removeMedFromPrescription(idx)} className="p-2 text-slate-300 hover:text-rose-600 transition-colors">
                                         <X className="w-4 h-4" />
                                      </button>
                                   </div>
                                ))}
                                <button onClick={handleSavePrescription} className="w-full py-5 bg-blue-600 text-white font-black uppercase tracking-widest text-[10px] rounded-2xl shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all mt-4 flex items-center justify-center gap-2">
                                   <Save className="w-4 h-4" /> Issue Prescription
                                </button>
                             </div>
                           )}
                        </div>
                      </div>

                      {/* Past Prescriptions */}
                      <div className="lg:col-span-7 space-y-6">
                         <h3 className="text-xl font-black text-slate-900 tracking-tight flex items-center gap-3"><Clock className="w-5 h-5 text-slate-400" /> Past Orders</h3>
                         {prescriptions.filter(rx => rx.patientId === selectedPatient.id).length === 0 ? (
                           <div className="py-24 text-center bg-white rounded-[2.5rem] border border-dashed border-slate-200">
                             <p className="text-slate-400 font-bold text-sm">No pharmaceutical records found.</p>
                           </div>
                         ) : (
                           prescriptions.filter(rx => rx.patientId === selectedPatient.id).map(rx => (
                             <div key={rx.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 group">
                                <div className="flex justify-between items-start mb-6">
                                   <div>
                                      <div className="flex items-center gap-3 mb-1">
                                        <h4 className="text-sm font-black text-slate-900 uppercase tracking-wider">RX #{rx.id.slice(-6)}</h4>
                                        <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[9px] font-black uppercase tracking-widest">Active Record</span>
                                      </div>
                                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{rx.date} • Dr. {rx.doctorName}</p>
                                   </div>
                                   <div className="flex gap-2">
                                      <button onClick={() => printPrescription(rx)} className="p-3 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-600 hover:text-white transition-all shadow-sm">
                                         <Printer className="w-5 h-5" />
                                      </button>
                                      <button onClick={() => handleDeletePrescription(rx.id)} className="p-3 bg-rose-50 text-rose-400 rounded-2xl hover:bg-rose-500 hover:text-white transition-all shadow-sm opacity-0 group-hover:opacity-100">
                                         <Trash2 className="w-5 h-5" />
                                      </button>
                                   </div>
                                </div>
                                <div className="divide-y divide-slate-50">
                                   {rx.medicines.map((m, i) => (
                                      <div key={i} className="py-4 first:pt-0 last:pb-0 flex justify-between items-center">
                                         <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400">
                                               <Pill className="w-5 h-5" />
                                            </div>
                                            <div>
                                               <p className="font-black text-slate-900 text-sm">{m.name}</p>
                                               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{m.dosage}</p>
                                            </div>
                                         </div>
                                         <div className="text-right">
                                            <p className="text-[10px] font-black text-slate-900 uppercase tracking-widest">{m.frequency}</p>
                                            <p className="text-[10px] font-bold text-blue-500 uppercase tracking-widest">{m.duration}</p>
                                         </div>
                                      </div>
                                   ))}
                                </div>
                             </div>
                           ))
                         )}
                      </div>
                    </div>
                 )}
              </div>
           </div>
         </div>
      )}
    </div>
  );
};

// Sub-components
const SearchIcon = () => (
  <svg className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2.5"><circle cx="11" cy="11" r="8"/><path strokeLinecap="round" strokeLinejoin="round" d="m21 21-4.3-4.3"/></svg>
);

const TabButton = ({ active, onClick, icon, label }: any) => (
  <button 
    onClick={onClick} 
    className={`flex-1 flex items-center justify-center gap-2 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
      active ? 'bg-blue-600 text-white shadow-xl shadow-blue-200' : 'text-slate-400 hover:bg-slate-50'
    }`}
  >
    {icon} {label}
  </button>
);

const DataRow = ({ label, value }: { label: string; value: string }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">{label}</p>
    <p className="text-lg font-black text-slate-900 tracking-tight">{value}</p>
  </div>
);

export default PatientsView;

import React, { useState, useMemo } from 'react';
import { useData } from '../context/DataContext';
import { Patient, PatientHistory, Prescription, StaffUser } from '../types';
// Import User icon from lucide-react
import { Trash2, Printer, Plus, FileText, Pill, X, Save, Clock, ClipboardList, User } from 'lucide-react';

interface Props {
  user: StaffUser;
  t: (key: string) => string;
}

const PatientsView: React.FC<Props> = ({ user, t }) => {
  const { 
    patients, addNewPatient, deletePat, 
    patientHistory, addNewHistory, prescriptions, addNewPrescription, removePrescription 
  } = useData();

  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // New Patient Form
  const [name, setName] = useState('');
  const [age, setAge] = useState('');
  const [phone, setPhone] = useState('');
  const [condition, setCondition] = useState('');

  // History Form
  const [diagnosis, setDiagnosis] = useState('');
  const [treatment, setTreatment] = useState('');
  const [notes, setNotes] = useState('');

  // Prescription Builder State
  const [medName, setMedName] = useState('');
  const [medDosage, setMedDosage] = useState('');
  const [medFrequency, setMedFrequency] = useState('');
  const [medDuration, setMedDuration] = useState('');
  const [currentMeds, setCurrentMeds] = useState<{name:string, dosage:string, frequency:string, duration:string}[]>([]);

  const [detailTab, setDetailTab] = useState<'info' | 'history' | 'prescription'>('info');

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault();
    const newPatient: Patient = {
      id: Date.now().toString(),
      name,
      age: parseInt(age),
      phone,
      lastVisit: new Date().toISOString().split('T')[0],
      medicalHistory: [],
      condition: condition || 'Checkup'
    };
    await addNewPatient(newPatient);
    setShowAddModal(false);
    setName(''); setAge(''); setPhone(''); setCondition('');
  };

  const handleDeletePatient = async (id: string, name: string) => {
    if (window.confirm(`${t('confirmDelete') || 'Are you sure you want to delete'} (${name})?`)) {
      await deletePat(id);
    }
  };

  const handleAddHistory = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatient) return;
    const newHistory: PatientHistory = {
      id: Date.now().toString(),
      patientId: selectedPatient.id,
      date: new Date().toISOString().split('T')[0],
      diagnosis,
      treatment,
      notes,
      doctorName: user?.name || 'Dr.'
    };
    await addNewHistory(newHistory);
    setDiagnosis(''); setTreatment(''); setNotes('');
  };

  const filteredPatients = useMemo(() => {
    return patients.filter(p => 
      p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
      p.phone.includes(searchTerm)
    );
  }, [patients, searchTerm]);

  const addMedToPrescription = () => {
    if (!medName || !medDosage) return;
    setCurrentMeds([...currentMeds, { 
      name: medName, 
      dosage: medDosage, 
      frequency: medFrequency, 
      duration: medDuration 
    }]);
    setMedName(''); setMedDosage(''); setMedFrequency(''); setMedDuration('');
  };

  const removeMedFromPrescription = (idx: number) => {
    setCurrentMeds(prev => prev.filter((_, i) => i !== idx));
  };

  const handleSavePrescription = async () => {
    if (!selectedPatient || currentMeds.length === 0) return;
    const newRx: Prescription = { 
        id: Date.now().toString(), 
        patientId: selectedPatient.id, 
        doctorName: user?.name || 'Dr.', 
        date: new Date().toISOString().split('T')[0], 
        medicines: currentMeds 
    };
    await addNewPrescription(newRx);
    setCurrentMeds([]);
  };

  const handleDeletePrescription = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this prescription record?')) {
      await removePrescription(id);
    }
  };

  const printPrescription = (rx: Prescription) => {
    const printWindow = window.open('', '', 'height=600,width=800');
    if (!printWindow) return;
    const patient = patients.find(p => p.id === rx.patientId);

    printWindow.document.write(`
      <html>
        <head>
          <title>Prescription - ${patient?.name}</title>
          <style>
            body { font-family: 'Inter', sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; }
            .header { text-align: center; border-bottom: 3px solid #2563eb; padding-bottom: 20px; margin-bottom: 30px; }
            .logo { font-size: 32px; font-weight: 900; color: #2563eb; letter-spacing: -1px; margin-bottom: 2px; }
            .sub-logo { font-size: 12px; font-weight: 800; color: #059669; letter-spacing: 3px; text-transform: uppercase; }
            .clinic-info { font-size: 13px; color: #64748b; margin-top: 10px; font-weight: 500; }
            .patient-box { background: #f8fafc; padding: 25px; border-radius: 16px; border: 1px solid #e2e8f0; display: flex; justify-content: space-between; margin-bottom: 40px; }
            .rx-symbol { font-size: 56px; font-weight: bold; color: #2563eb; font-family: serif; margin-bottom: 20px; line-height: 1; }
            .med-list { width: 100%; border-collapse: collapse; margin-bottom: 60px; }
            .med-list th { text-align: left; border-bottom: 2px solid #e2e8f0; padding: 12px 8px; color: #64748b; font-size: 11px; text-transform: uppercase; letter-spacing: 1px; }
            .med-list td { padding: 16px 8px; border-bottom: 1px solid #f1f5f9; font-size: 14px; font-weight: 600; }
            .med-name { font-size: 16px; font-weight: 800; color: #0f172a; }
            .footer { margin-top: 80px; display: flex; justify-content: space-between; font-size: 13px; align-items: flex-end; border-top: 1px solid #f1f5f9; pt: 20px; }
            .signature-space { text-align: center; width: 220px; }
            .signature-line { border-top: 2px solid #0f172a; margin-bottom: 8px; margin-top: 40px; }
            .tagline { font-style: italic; color: #94a3b8; font-weight: 500; }
          </style>
        </head>
        <body>
          <div class="header">
            <div class="logo">DHOOL</div>
            <div class="sub-logo">Dental Clinic & Pharmacy</div>
            <div class="clinic-info">Maka Al-Mukarama Rd, Mogadishu | Tel: +252 61 5000000</div>
          </div>
          <div class="patient-box">
            <div>
              <div style="color:#64748b; font-size:10px; text-transform:uppercase; font-weight:800; margin-bottom:4px;">Patient Details</div>
              <div style="font-weight:900; font-size:20px; color: #0f172a;">${patient?.name}</div>
              <div style="margin-top:4px; font-weight:600;">Age: ${patient?.age} | Sex: M/F</div>
            </div>
            <div style="text-align:right;">
              <div style="color:#64748b; font-size:10px; text-transform:uppercase; font-weight:800; margin-bottom:4px;">Prescription Date</div>
              <div style="font-weight:900; font-size:16px;">${rx.date}</div>
              <div style="margin-top:4px; font-weight:600; color: #2563eb;">Dr. ${rx.doctorName}</div>
            </div>
          </div>
          <div class="rx-symbol">Rx</div>
          <table class="med-list">
            <thead>
              <tr>
                <th width="40%">Medication</th>
                <th width="20%">Dosage</th>
                <th width="20%">Frequency</th>
                <th width="20%">Duration</th>
              </tr>
            </thead>
            <tbody>
              ${rx.medicines.map(m => `
                <tr>
                  <td><div class="med-name">${m.name}</div></td>
                  <td>${m.dosage}</td>
                  <td>${m.frequency}</td>
                  <td>${m.duration}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>
          <div class="footer">
            <div class="tagline">Providing quality care since 2024.</div>
            <div class="signature-space">
              <div class="signature-line"></div>
              <div style="font-weight:800; text-transform:uppercase; font-size:11px;">Authorized Signature</div>
            </div>
          </div>
        </body>
      </html>
    `);
    printWindow.document.close();
    setTimeout(() => {
      printWindow.print();
    }, 500);
  };

  return (
    <div className="p-4 md:p-6 pb-24 md:pb-6 max-w-7xl mx-auto">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">{t('patients')}</h2>
          <p className="text-slate-500 font-medium">Manage patient registry and clinical histories.</p>
        </div>

        <div className="flex flex-1 w-full md:w-auto gap-3">
          <div className="relative flex-1 max-w-md">
            <SearchIcon />
            <input 
              type="text" 
              placeholder={t('searchPlaceholder') || 'Search by name or phone...'} 
              className="w-full pl-12 pr-4 py-3.5 bg-white border border-slate-200 rounded-2xl focus:outline-none focus:border-blue-500 shadow-sm font-bold text-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
             onClick={() => setShowAddModal(true)}
             className="bg-blue-600 text-white px-6 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 hover:bg-blue-700 transition-all flex items-center gap-2 whitespace-nowrap"
          >
            <Plus className="w-4 h-4" /> Register Patient
          </button>
        </div>
      </div>

