// Check if configuration is a placeholder
const isConfigInvalid = auth.app.options.apiKey === "YOUR_API_KEY_HERE";

// Global flag to stop hitting Firestore if it's missing or down
let isDbOffline = isConfigInvalid; // Default to offline if config is placeholder

if (isDbOffline) {
    console.warn("%c RUNNING IN OFFLINE MODE ", "background: #f59e0b; color: black; font-weight: bold; padding: 4px;");
    console.warn("Firebase keys are placeholders. Using Local Storage for data persistence.");
}

// Helper to handle Firestore requests with Local Storage Fallback & Sync
const handleRequest = async <T>(
  operation: () => Promise<T>,
  localKey: string,
  action: 'get' | 'insert' | 'update' | 'delete',
  payload?: any
): Promise<T | any> => {
  // 1. Circuit Breaker: If we already know DB is missing, skip straight to local storage
  if (isDbOffline) {
    return handleLocalFallback(localKey, action, payload);
  }

  try {
    const data = await operation();

    // 2. SUCCESS SYNC: Update Local Storage even on successful remote operation.
    try {
        const currentLocal = JSON.parse(localStorage.getItem(localKey) || '[]');

        if (action === 'get' && Array.isArray(data)) {
           localStorage.setItem(localKey, JSON.stringify(data));
        } else if (action === 'insert') {
           // Avoid duplicates by ID
           const filtered = currentLocal.filter((i:any) => i.id !== payload.id);
           localStorage.setItem(localKey, JSON.stringify([data, ...filtered]));
        } else if (action === 'update' && payload?.id) {
           const updated = currentLocal.map((i:any) => i.id === payload.id ? {...i, ...payload.updates} : i);
           localStorage.setItem(localKey, JSON.stringify(updated));
        } else if (action === 'delete') {
           const updated = currentLocal.filter((i:any) => i.id !== payload);
           localStorage.setItem(localKey, JSON.stringify(updated));
        }
    } catch (syncError) {
        console.warn("Local cache sync failed", syncError);
    }

    return data;
  } catch (error: any) {
    // 3. Error Handling: Detect missing DB and activate Circuit Breaker
    if (error.code === 'not-found' || error.code === 'permission-denied' || (error.message && error.message.includes('database'))) {
        if (!isDbOffline) {
            console.warn("%c FIREBASE DATABASE ERROR ", "background: orange; color: black; font-weight: bold; padding: 4px;");
            console.warn(`Error: ${error.message}. Switching to LOCAL STORAGE.`);
            isDbOffline = true; // Stop future requests
        }
    } else {
        console.warn(`Firebase ${action} failed for ${localKey}. Using Local Storage.`, error);
    }

    // 4. Execute Fallback
    return handleLocalFallback(localKey, action, payload);
  }
};

// Isolated Local Storage Logic
const handleLocalFallback = (localKey: string, action: string, payload: any) => {
    let localData = JSON.parse(localStorage.getItem(localKey) || '[]');

    if (action === 'get') return localData;

    if (action === 'insert') {
      const newItem = Array.isArray(payload) ? payload[0] : payload;
      if (!newItem.id) newItem.id = Date.now().toString();
      // Deduplicate
      const filtered = localData.filter((i:any) => i.id !== newItem.id);
      const updatedList = [newItem, ...filtered];
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return newItem;
    }

    if (action === 'update') {
      const updatedList = localData.map((item: any) => item.id === payload.id ? { ...item, ...payload.updates } : item);
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return payload.updates;
