import React, { useState, useMemo } from 'react';
import { 
  BarChart3, TrendingUp, TrendingDown, Users, Package, Wallet, ShoppingBag, Calendar, Stethoscope, Filter, Search, ChevronRight
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { useData } from '../context/DataContext';

const ReportsView: React.FC = () => {
  const { patients, inventory, invoices, expenses, salaries } = useData();

  // Date states
  const today = new Date().toISOString().split('T')[0];
  const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];

  const [reportRange, setReportRange] = useState('This Month');
  const [startDate, setStartDate] = useState(firstDayOfMonth);
  const [endDate, setEndDate] = useState(today);

  // Filtering Logic
  const filteredData = useMemo(() => {
    let start = new Date(startDate);
    let end = new Date(endDate);
    end.setHours(23, 59, 59, 999);

    if (reportRange === 'Today') {
      const t = new Date();
      start = new Date(t.setHours(0,0,0,0));
      end = new Date(t.setHours(23,59,59,999));
    } else if (reportRange === 'This Month') {
      start = new Date(new Date().getFullYear(), new Date().getMonth(), 1);
      end = new Date();
    } else if (reportRange === 'Last Quarter') {
      start = new Date();
      start.setMonth(start.getMonth() - 3);
      end = new Date();
    }

    const filterFn = (item: { date: string }) => {
      const d = new Date(item.date);
      return d >= start && d <= end;
    };

    return {
      invoices: invoices.filter(filterFn),
      expenses: expenses.filter(filterFn),
      salaries: salaries.filter(filterFn)
    };
  }, [invoices, expenses, salaries, reportRange, startDate, endDate]);

  // Unified Financial Computation using filtered data
  const grossRevenue = filteredData.invoices
    .filter(i => i.status === 'Paid')
    .reduce((acc, i) => acc + i.amount, 0);

  const totalRefunds = filteredData.invoices
    .filter(i => i.status === 'Refunded')
    .reduce((acc, i) => acc + Math.abs(i.amount), 0);

  const operationalExpenses = filteredData.expenses.reduce((acc, e) => acc + e.amount, 0);
  const payrollTotal = filteredData.salaries.reduce((acc, s) => acc + s.amount, 0);

  const totalOutflow = operationalExpenses + payrollTotal + totalRefunds;
  const netRevenue = grossRevenue - totalRefunds;
  const netProfit = netRevenue - (operationalExpenses + payrollTotal);

  const reportData = [
    { name: 'Revenue', val: grossRevenue, fill: '#3b82f6' },
    { name: 'Refunds', val: totalRefunds, fill: '#f43f5e' },
    { name: 'Operations', val: operationalExpenses, fill: '#fb923c' },
    { name: 'Payroll', val: payrollTotal, fill: '#8b5cf6' },
  ];

  return (
    <div className="space-y-10 animate-in fade-in duration-500 max-w-7xl mx-auto pb-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Financial Intelligence</h1>
          <p className="text-slate-500 font-medium">Consolidated view of clinical revenue and overheads.</p>
        </div>

        <div className="bg-white p-4 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col md:flex-row items-center gap-4">
           <div className="flex items-center gap-2">
              <Filter className="w-4 h-4 text-blue-600" />
              <select 
                value={reportRange} 
                onChange={e => setReportRange(e.target.value)} 
                className="bg-slate-50 px-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest outline-none border-none focus:ring-2 focus:ring-blue-500/20"
              >
                <option>Today</option>
                <option>This Month</option>
                <option>Last Quarter</option>
                <option value="Custom">Custom Range</option>
              </select>
           </div>

           {(reportRange === 'Custom' || reportRange === 'Today') && (
             <div className="flex items-center gap-3 animate-in slide-in-from-right-4">
                <div className="flex items-center gap-2">
                   <span className="text-[9px] font-black text-slate-400 uppercase">From</span>
                   <input 
                    type="date" 
                    value={startDate} 
                    onChange={e => setStartDate(e.target.value)}
                    className="bg-slate-50 px-3 py-2 rounded-xl text-[10px] font-bold border-none outline-none focus:bg-white focus:ring-2 focus:ring-blue-500/20"
                   />
                </div>
                <div className="flex items-center gap-2">
                   <span className="text-[9px] font-black text-slate-400 uppercase">To</span>
                   <input 
                    type="date" 
                    value={endDate} 
                    onChange={e => setEndDate(e.target.value)}
                    className="bg-slate-50 px-3 py-2 rounded-xl text-[10px] font-bold border-none outline-none focus:bg-white focus:ring-2 focus:ring-blue-500/20"
                   />
                </div>
             </div>
           )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="bg-gradient-to-br from-blue-600 to-indigo-800 p-10 rounded-[3rem] text-white shadow-2xl relative overflow-hidden group">
           <div className="absolute -top-10 -right-10 opacity-10 group-hover:scale-125 transition-transform duration-700">
              <TrendingUp className="w-48 h-48" />
           </div>
           <p className="text-blue-100 font-black uppercase tracking-[0.2em] text-[10px] mb-2">Net Cash Inflow</p>
           <h2 className="text-5xl font-black tracking-tighter">${netRevenue.toLocaleString()}</h2>
           <div className="mt-8 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest bg-white/10 w-fit px-4 py-2 rounded-full backdrop-blur-md">
             <Calendar className="w-3 h-3" /> {reportRange === 'Today' ? `Report for ${startDate}` : `${startDate} - ${endDate}`}
           </div>
        </div>

        <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col justify-between">
           <div>
              <p className="text-slate-400 font-black uppercase tracking-[0.2em] text-[10px] mb-2">Operational Outflow</p>
              <h3 className="text-4xl font-black text-rose-600 tracking-tighter">-${totalOutflow.toLocaleString()}</h3>
           </div>
           <p className="text-[10px] font-bold text-slate-400 mt-4 italic">Includes ${payrollTotal.toLocaleString()} Staff Payroll</p>
        </div>

        <div className="bg-emerald-600 p-10 rounded-[3rem] text-white shadow-2xl relative overflow-hidden group">
           <div className="absolute -bottom-10 -left-10 opacity-10 group-hover:scale-125 transition-transform duration-700">
              <Wallet className="w-48 h-48" />
           </div>
           <p className="text-emerald-100 font-black uppercase tracking-[0.2em] text-[10px] mb-2">Net Fiscal Profit</p>
           <h2 className="text-5xl font-black tracking-tighter">${netProfit.toLocaleString(undefined, { minimumFractionDigits: 2 })}</h2>
           <div className="mt-8 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest bg-white/10 w-fit px-4 py-2 rounded-full backdrop-blur-md">
             {netProfit >= 0 ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />} 
             {netProfit >= 0 ? 'Surplus' : 'Deficit'}
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
         <div className="lg:col-span-8 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm min-h-[500px] flex flex-col">
            <h3 className="text-2xl font-black text-slate-900 mb-10 tracking-tight">Revenue Breakdown</h3>
            <div className="flex-1 w-full">
               <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={reportData}>
                     <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                     <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 800}} />
                     <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                     <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '2rem', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.1)'}} />
                     <Bar dataKey="val" radius={[15, 15, 0, 0]} barSize={60}>
                        {reportData.map((entry, index) => (
                           <Cell key={`cell-${index}`} fill={entry.fill} />
                        ))}
                     </Bar>
                  </BarChart>
               </ResponsiveContainer>
            </div>
         </div>

         <div className="lg:col-span-4 space-y-8">
            <div className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm">
               <h3 className="text-xl font-black text-slate-900 mb-8 tracking-tight">Period Stats</h3>
               <div className="space-y-6">
                  <StatRow icon={<Users className="text-blue-600" />} label="New Registrations" val={patients.filter(p => new Date(p.lastVisit) >= new Date(startDate)).length} />
                  <StatRow icon={<ShoppingBag className="text-emerald-600" />} label="Transactions" val={filteredData.invoices.length} />
                  <StatRow icon={<Stethoscope className="text-indigo-600" />} label="Avg. Order Value" val={filteredData.invoices.length ? `$${(grossRevenue / filteredData.invoices.length).toFixed(0)}` : '$0'} />
                  <StatRow icon={<Package className="text-rose-600" />} label="Stock Alerts" val={inventory.filter(i => i.stock < 10).length} />
               </div>
            </div>

            <div className="bg-slate-900 p-8 rounded-[3rem] text-white shadow-2xl">
               <h3 className="text-xl font-black mb-6 tracking-tight">Export Segment</h3>
               <div className="grid grid-cols-2 gap-4">
                  <button className="py-4 bg-white/10 hover:bg-white/20 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">PDF Report</button>
                  <button className="py-4 bg-white/10 hover:bg-white/20 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">CSV Data</button>
               </div>
            </div>
         </div>
      </div>
    </div>
  );
};

const StatRow = ({ icon, label, val }: any) => (
  <div className="flex items-center justify-between group">
     <div className="flex items-center gap-4">
        <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center transition-all group-hover:scale-110">{icon}</div>
        <span className="text-xs font-bold text-slate-500">{label}</span>
     </div>
     <span className="text-lg font-black text-slate-900">{val}</span>
  </div>
);

