                    >
                      {isAiLoading ? 'Analyzing...' : <><Sparkles className="w-4 h-4" /> AI Diagnostics</>}
                    </button>
                    <button onClick={() => setSelectedPatient(null)} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition-all border border-white/10">
                      <X className="w-6 h-6" />
