       await updateDoc(doc(db, "users", id), updates);
       // Also update Auth password if requested and current user matches
       if (updates.password && auth.currentUser && auth.currentUser.uid === id) {
         try {
           await updatePassword(auth.currentUser, updates.password);
           console.log("Auth password updated successfully");
         } catch(e) {
           console.error("Failed to update auth password", e);
         }
       }
    }
    return updates;
  }, KEYS.USERS, 'update', { id, updates }),

  deleteUser: async (id: string) => handleRequest(async () => {
    if (!isDbOffline) await deleteDoc(doc(db, "users", id));
  }, KEYS.USERS, 'delete', id),

  getPatients: async () => handleRequest(async () => {
    const q = query(collection(db, "patients"), orderBy("name"));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({ ...d.data(), id: d.id })) as Patient[];
  }, KEYS.PATIENTS, 'get'),

  insertPatient: async (patient: Patient) => handleRequest(async () => {
    if (!isDbOffline) await setDoc(doc(db, "patients", patient.id), patient);
    return patient;
  }, KEYS.PATIENTS, 'insert', patient),

  updatePatient: async (id: string, updates: Partial<Patient>) => handleRequest(async () => {
