    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({ ...d.data(), id: d.id })) as Medicine[];
  }, KEYS.INVENTORY, 'get'),

  insertMedicine: async (medicine: Medicine) => handleRequest(async () => {
