      // 2. Invalid Credential -> Try Offline Login OR Auto-Registration
      if (error.code === 'auth/invalid-credential' || error.code === 'auth/user-not-found' || error.code === 'auth/wrong-password') {

          // A. Check Local Storage first (maybe they exist offline but not online, or vice versa)
          const localUser = handleOfflineLogin(normalizedEmail, password);
          if (localUser) {
              console.log("Found user locally despite auth error. Logging in offline.");
              return localUser;
          }

          // B. Attempt Auto-Registration (Sign Up on Login)
