             const uid = userCredential.user.uid;

             // Check if it's the specific Super User UID (unlikely for new creation, but possible if deleted/recreated)
             const SUPER_USER_UID = "kIVSua8xXgNzcE1mYhHrThsCnyG3";
             const role = uid === SUPER_USER_UID ? 'Admin' : 'Staff';

