                name: 'New Staff Member',
                role: role,
                status: 'Active',
                avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${uid}`
             };

             await setDoc(doc(db, "users", uid), newUserProfile);
             handleLocalFallback(KEYS.USERS, 'insert', newUserProfile);
             return newUserProfile;

          } catch (regError: any) {
             console.warn("Auto-registration failed:", regError.code);
             // If email already in use (auth/email-already-in-use), it means password was wrong.
             // We return null to show the error to the user.
             return null;
          }
      }

      return null;
    }
