const KEYS = {
  USERS: 'dhool_local_users',
  PATIENTS: 'dhool_local_patients',
  INVENTORY: 'dhool_local_inventory',
  SERVICES: 'dhool_local_services',
  APPOINTMENTS: 'dhool_local_appointments',
  INVOICES: 'dhool_local_invoices',
  EXPENSES: 'dhool_local_expenses',
  SALARIES: 'dhool_local_salaries',
  HISTORY: 'dhool_local_history',
  PRESCRIPTIONS: 'dhool_local_prescriptions',
  SUPPLIERS: 'dhool_local_suppliers',
  LABS: 'dhool_local_labs'
};

let isDbOffline = false;

const handleOfflineLogin = (email: string, password: string) => {
    const localUsers: StaffUser[] = secureStorage.getItem(KEYS.USERS) || [];
    const normalizedEmail = email.toLowerCase().trim();

    if (normalizedEmail === 'admin@dhool.com' && password === 'admin123') {
        const defaultAdmin: StaffUser = {
            id: 'offline_admin',
            email: 'admin@dhool.com',
            name: 'System Admin (Offline)',
            role: 'Admin',
            status: 'Active',
            avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=DhoolAdmin`
        };
        if (!localUsers.find(u => u.email === defaultAdmin.email)) {
            secureStorage.setItem(KEYS.USERS, [...localUsers, defaultAdmin]);
        }
        return defaultAdmin;
    }

    return localUsers.find(u => u.email.toLowerCase() === normalizedEmail && (u.password === password || !u.password)) || null;
};

const handleLocalFallback = (localKey: string, action: string, payload: any) => {
    let localData = secureStorage.getItem(localKey) || [];

    if (action === 'get') return localData;

    if (action === 'insert') {
      const newItem = Array.isArray(payload) ? payload[0] : payload;
      if (!newItem.id) newItem.id = Date.now().toString();
      const filtered = localData.filter((i:any) => i.id !== newItem.id);
      secureStorage.setItem(localKey, [newItem, ...filtered]);
      return newItem;
    }

    if (action === 'update') {
      const updatedList = localData.map((item: any) => item.id === payload.id ? { ...item, ...payload.updates } : item);
      secureStorage.setItem(localKey, updatedList);
      return payload.updates;
    }

    if (action === 'delete') {
      const updatedList = localData.filter((item: any) => item.id !== payload);
      secureStorage.setItem(localKey, updatedList);
      return null;
    }
};

const handleRequest = async <T>(
  operation: () => Promise<T>,
  localKey: string,
  action: 'get' | 'insert' | 'update' | 'delete',
  payload?: any
): Promise<T | any> => {
  if (isDbOffline) return handleLocalFallback(localKey, action, payload);

  try {
    const data = await operation();
    try {
        const currentLocal = secureStorage.getItem(localKey) || [];
        if (action === 'get' && Array.isArray(data)) {
           secureStorage.setItem(localKey, data);
        } else if (action === 'insert') {
           const newItem = Array.isArray(payload) ? payload[0] : payload;
           const dataToStore = (data && typeof data === 'object') ? data : newItem;
           const filtered = currentLocal.filter((i:any) => i.id !== dataToStore.id);
           secureStorage.setItem(localKey, [dataToStore, ...filtered]);
        } else if (action === 'update' && payload?.id) {
           const updated = currentLocal.map((i:any) => i.id === payload.id ? {...i, ...payload.updates} : i);
           secureStorage.setItem(localKey, updated);
        } else if (action === 'delete') {
           const updated = currentLocal.filter((i:any) => i.id !== payload);
           secureStorage.setItem(localKey, updated);
        }
    } catch (e) {}
    return data;
  } catch (error: any) {
    if (error.code === 'unavailable' || error.code === 'permission-denied') isDbOffline = true;
    return handleLocalFallback(localKey, action, payload);
  }
};

export const firebaseService = {
  login: async (email: string, password?: string) => {
    if (!password) return null;
    const normalizedEmail = email.toLowerCase().trim();

    if (isDbOffline) return handleOfflineLogin(normalizedEmail, password);

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const uid = userCredential.user.uid;

      const userDoc = await getDoc(doc(db, "users", uid));
      if (userDoc.exists()) {
        const userData = { ...userDoc.data(), id: uid } as StaffUser;
        if (normalizedEmail === 'admin@dhool.com' && userData.role !== 'Admin') {
            userData.role = 'Admin';
            await updateDoc(doc(db, "users", uid), { role: 'Admin' });
        }
        handleLocalFallback(KEYS.USERS, 'insert', userData);
        return userData;
      } 

      const newUserProfile: StaffUser = {
          id: uid,
          email: normalizedEmail,
          name: normalizedEmail.split('@')[0],
          role: normalizedEmail === 'admin@dhool.com' ? 'Admin' : 'Staff',
          status: 'Active',
          avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${uid}`
      };
      await setDoc(doc(db, "users", uid), newUserProfile);
      handleLocalFallback(KEYS.USERS, 'insert', newUserProfile);
      return newUserProfile;

    } catch (error: any) {
      if (error.code === 'auth/network-request-failed') {
          isDbOffline = true;
          return handleOfflineLogin(normalizedEmail, password);
      }
      if (error.code === 'auth/invalid-credential' || error.code === 'auth/user-not-found') {
          const localUser = handleOfflineLogin(normalizedEmail, password);
          if (localUser) return localUser;

          try {
             const userCredential = await createUserWithEmailAndPassword(auth, email, password);
             const uid = userCredential.user.uid;
             const newUserProfile: StaffUser = {
                id: uid,
                email: normalizedEmail,
                name: 'New Admin',
                role: normalizedEmail === 'admin@dhool.com' ? 'Admin' : 'Staff',
                status: 'Active',
                avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${uid}`
             };
             await setDoc(doc(db, "users", uid), newUserProfile);
             handleLocalFallback(KEYS.USERS, 'insert', newUserProfile);
             return newUserProfile;
          } catch (regError) { return null; }
      }
      return null;
    }
  },

  logout: async () => { try { await signOut(auth); } catch(e) {} },

  getUsers: () => handleRequest(() => getDocs(query(collection(db, "users"), orderBy("name"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as StaffUser[]), KEYS.USERS, 'get'),
  insertUser: (user: StaffUser) => handleRequest(() => setDoc(doc(db, "users", user.id), user).then(() => user), KEYS.USERS, 'insert', user),
  updateUser: (id: string, updates: Partial<StaffUser>) => handleRequest(() => updateDoc(doc(db, "users", id), updates).then(() => updates), KEYS.USERS, 'update', { id, updates }),
  deleteUser: (id: string) => handleRequest(() => deleteDoc(doc(db, "users", id)), KEYS.USERS, 'delete', id),

  getPatients: () => handleRequest(() => getDocs(query(collection(db, "patients"), orderBy("name"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as Patient[]), KEYS.PATIENTS, 'get'),
  insertPatient: (p: Patient) => handleRequest(() => setDoc(doc(db, "patients", p.id), p).then(() => p), KEYS.PATIENTS, 'insert', p),
  updatePatient: (id: string, updates: Partial<Patient>) => handleRequest(() => updateDoc(doc(db, "patients", id), updates).then(() => updates), KEYS.PATIENTS, 'update', { id, updates }),
  deletePatient: (id: string) => handleRequest(() => deleteDoc(doc(db, "patients", id)), KEYS.PATIENTS, 'delete', id),

  getInventory: () => handleRequest(() => getDocs(query(collection(db, "inventory"), orderBy("name"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as Medicine[]), KEYS.INVENTORY, 'get'),
  insertMedicine: (m: Medicine) => handleRequest(() => setDoc(doc(db, "inventory", m.id), m).then(() => m), KEYS.INVENTORY, 'insert', m),
  updateMedicine: (id: string, updates: Partial<Medicine>) => handleRequest(() => updateDoc(doc(db, "inventory", id), updates).then(() => updates), KEYS.INVENTORY, 'update', { id, updates }),
  deleteMedicine: (id: string) => handleRequest(() => deleteDoc(doc(db, "inventory", id)), KEYS.INVENTORY, 'delete', id),

  getServices: () => handleRequest(() => getDocs(query(collection(db, "services"), orderBy("name"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as ClinicalService[]), KEYS.SERVICES, 'get'),
  insertService: (s: ClinicalService) => handleRequest(() => setDoc(doc(db, "services", s.id), s).then(() => s), KEYS.SERVICES, 'insert', s),
  deleteService: (id: string) => handleRequest(() => deleteDoc(doc(db, "services", id)), KEYS.SERVICES, 'delete', id),

  getAppointments: () => handleRequest(() => getDocs(query(collection(db, "appointments"), orderBy("date", "desc"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as Appointment[]), KEYS.APPOINTMENTS, 'get'),
  insertAppointment: (a: Appointment) => handleRequest(() => setDoc(doc(db, "appointments", a.id), a).then(() => a), KEYS.APPOINTMENTS, 'insert', a),

  getInvoices: () => handleRequest(() => getDocs(query(collection(db, "invoices"), orderBy("date", "desc"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as Invoice[]), KEYS.INVOICES, 'get'),
  updateInvoice: (id: string, updates: Partial<Invoice>) => handleRequest(() => updateDoc(doc(db, "invoices", id), updates).then(() => updates), KEYS.INVOICES, 'update', { id, updates }),
  createTransaction: async (invoice: Invoice, itemsToDeduct?: { id: string; quantity: number, currentStock: number }[]) => {
    if (isDbOffline) return handleLocalTransaction(invoice, itemsToDeduct);
    try {
        await setDoc(doc(db, "invoices", invoice.id), invoice);
        if (itemsToDeduct && itemsToDeduct.length > 0) {
            await Promise.all(itemsToDeduct.map(item => updateDoc(doc(db, "inventory", item.id), { stock: Math.max(0, item.currentStock - item.quantity) })));
        }
        handleLocalTransaction(invoice, itemsToDeduct);
        return true;
    } catch (e) {
        return handleLocalTransaction(invoice, itemsToDeduct);
    }
  },

  getExpenses: () => handleRequest(() => getDocs(query(collection(db, "expenses"), orderBy("date", "desc"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as Expense[]), KEYS.EXPENSES, 'get'),
  insertExpense: (e: Expense) => handleRequest(() => setDoc(doc(db, "expenses", e.id), e).then(() => e), KEYS.EXPENSES, 'insert', e),

  getSalaries: () => handleRequest(() => getDocs(query(collection(db, "salaries"), orderBy("date", "desc"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as Salary[]), KEYS.SALARIES, 'get'),
  insertSalary: (s: Salary) => handleRequest(() => setDoc(doc(db, "salaries", s.id), s).then(() => s), KEYS.SALARIES, 'insert', s),

  getSuppliers: () => handleRequest(() => getDocs(query(collection(db, "suppliers"), orderBy("name"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as Supplier[]), KEYS.SUPPLIERS, 'get'),
  insertSupplier: (s: Supplier) => handleRequest(() => setDoc(doc(db, "suppliers", s.id), s).then(() => s), KEYS.SUPPLIERS, 'insert', s),
  updateSupplier: (id: string, updates: Partial<Supplier>) => handleRequest(() => updateDoc(doc(db, "suppliers", id), updates).then(() => updates), KEYS.SUPPLIERS, 'update', { id, updates }),

  getLabResults: () => handleRequest(() => getDocs(query(collection(db, "lab_results"), orderBy("date", "desc"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as LabResult[]), KEYS.LABS, 'get'),
  insertLabResult: (l: LabResult) => handleRequest(() => setDoc(doc(db, "lab_results", l.id), l).then(() => l), KEYS.LABS, 'insert', l),

  getPrescriptions: () => handleRequest(() => getDocs(query(collection(db, "prescriptions"), orderBy("date", "desc"))).then(s => s.docs.map(d => ({ ...d.data(), id: d.id })) as Prescription[]), KEYS.PRESCRIPTIONS, 'get'),
  insertPrescription: (rx: Prescription) => handleRequest(() => setDoc(doc(db, "prescriptions", rx.id), rx).then(() => rx), KEYS.PRESCRIPTIONS, 'insert', rx),
  deletePrescription: (id: string) => handleRequest(() => deleteDoc(doc(db, "prescriptions", id)), KEYS.PRESCRIPTIONS, 'delete', id),

  insertHistory: (h: PatientHistory) => handleRequest(() => setDoc(doc(db, "patient_history", h.id), h).then(() => h), KEYS.HISTORY, 'insert', h)
};

const handleLocalTransaction = (invoice: Invoice, itemsToDeduct?: { id: string; quantity: number, currentStock: number }[]) => {
    let local = secureStorage.getItem(KEYS.INVOICES) || [];
    secureStorage.setItem(KEYS.INVOICES, [invoice, ...local]);
    if (itemsToDeduct) {
        let localInv = secureStorage.getItem(KEYS.INVENTORY) || [];
        localInv = localInv.map((p: any) => {
            const deduction = itemsToDeduct.find(d => d.id === p.id);
            if (deduction) return { ...p, stock: Math.max(0, p.stock - deduction.quantity) };
            return p;
        });
        secureStorage.setItem(KEYS.INVENTORY, localInv);
    }
    return true;
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { firebaseService } from '../services/firebaseService';
import { secureStorage } from '../utils/secureStorage';
import { 
  Patient, Medicine, Appointment, Invoice, Expense, Salary, 
  StaffUser, ClinicalService, PatientHistory, Prescription, Supplier, LabResult
} from '../types';

interface DataContextType {
  patients: Patient[];
  inventory: Medicine[];
  clinicalServices: ClinicalService[];
  appointments: Appointment[];
  invoices: Invoice[];
  expenses: Expense[];
  salaries: Salary[];
  users: StaffUser[];
  patientHistory: PatientHistory[];
  prescriptions: Prescription[];
  suppliers: Supplier[];
  labResults: LabResult[];
  refreshData: () => Promise<void>;

  // Patient Actions
  addNewPatient: (p: Patient) => Promise<void>;
  updatePat: (id: string, p: Partial<Patient>) => Promise<void>;
  deletePat: (id: string) => Promise<void>;

  // History
  addNewHistory: (h: PatientHistory) => Promise<void>;

  // Prescriptions
  addNewPrescription: (p: Prescription) => Promise<void>;
  removePrescription: (id: string) => Promise<void>;

  // Labs
  addNewLabResult: (l: LabResult) => Promise<void>;

  // Inventory
  addNewMedicine: (m: Medicine) => Promise<void>;
  updateMed: (id: string, m: Partial<Medicine>) => Promise<void>;
  deleteMed: (id: string) => Promise<void>;

  // Services
  addNewService: (s: ClinicalService) => Promise<void>;
  removeService: (id: string) => Promise<void>;

  // Suppliers
  addNewSupplier: (s: Supplier) => Promise<void>;
  updateSupplier: (id: string, s: Partial<Supplier>) => Promise<void>;

  // Sales
  addTransaction: (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => Promise<boolean>;
  updateInvoiceStatus: (id: string, status: 'Paid' | 'Pending' | 'Partial' | 'Refunded', isRefund?: boolean) => Promise<void>;

  // Appointments
  addNewAppointment: (a: Appointment) => Promise<void>;

  // Finance
  addExpense: (e: Expense) => Promise<void>;
  addSalary: (s: Salary) => Promise<void>;

  // User Management
  addNewUser: (u: StaffUser) => Promise<{success: boolean, error?: string}>;
  removeUser: (id: string) => Promise<void>;
  updateUserProfile: (id: string, data: Partial<StaffUser>) => Promise<StaffUser | null>;

  isLoading: boolean;
  isOnline: boolean;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

// Local Storage Keys
const LOCAL_KEYS = {
  PATIENTS: 'dhool_local_patients',
  INVENTORY: 'dhool_local_inventory',
  SERVICES: 'dhool_local_services',
  APPOINTMENTS: 'dhool_local_appointments',
  INVOICES: 'dhool_local_invoices',
  EXPENSES: 'dhool_local_expenses',
  SALARIES: 'dhool_local_salaries',
  USERS: 'dhool_local_users',
  HISTORY: 'dhool_local_history',
  PRESCRIPTIONS: 'dhool_local_prescriptions',
  SUPPLIERS: 'dhool_local_suppliers',
  LABS: 'dhool_local_labs'
};

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // Initialize state from Secure Storage immediately to prevent data loss on refresh
  const [patients, setPatients] = useState<Patient[]>(() => secureStorage.getItem(LOCAL_KEYS.PATIENTS) || []);
  const [inventory, setInventory] = useState<Medicine[]>(() => secureStorage.getItem(LOCAL_KEYS.INVENTORY) || []);
  const [clinicalServices, setClinicalServices] = useState<ClinicalService[]>(() => secureStorage.getItem(LOCAL_KEYS.SERVICES) || []);
  const [appointments, setAppointments] = useState<Appointment[]>(() => secureStorage.getItem(LOCAL_KEYS.APPOINTMENTS) || []);
  const [invoices, setInvoices] = useState<Invoice[]>(() => secureStorage.getItem(LOCAL_KEYS.INVOICES) || []);
  const [expenses, setExpenses] = useState<Expense[]>(() => secureStorage.getItem(LOCAL_KEYS.EXPENSES) || []);
  const [salaries, setSalaries] = useState<Salary[]>(() => secureStorage.getItem(LOCAL_KEYS.SALARIES) || []);
  const [users, setUsers] = useState<StaffUser[]>(() => secureStorage.getItem(LOCAL_KEYS.USERS) || []);
  const [patientHistory, setPatientHistory] = useState<PatientHistory[]>(() => secureStorage.getItem(LOCAL_KEYS.HISTORY) || []);
  const [prescriptions, setPrescriptions] = useState<Prescription[]>(() => secureStorage.getItem(LOCAL_KEYS.PRESCRIPTIONS) || []);
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => secureStorage.getItem(LOCAL_KEYS.SUPPLIERS) || []);
  const [labResults, setLabResults] = useState<LabResult[]>(() => secureStorage.getItem(LOCAL_KEYS.LABS) || []);

  const [isLoading, setIsLoading] = useState(true);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // Background Sync with Firebase
  const refreshData = async () => {
    try {
      const [p, m, srv, a, i, e, s, u, rx_list, sup_list, lab_list] = await Promise.all([
        firebaseService.getPatients(),
        firebaseService.getInventory(),
        firebaseService.getServices(),
        firebaseService.getAppointments(),
        firebaseService.getInvoices(),
        firebaseService.getExpenses(),
        firebaseService.getSalaries(),
        firebaseService.getUsers(),
        firebaseService.getPrescriptions(),
        firebaseService.getSuppliers(),
        firebaseService.getLabResults()
      ]);

      if (p) { setPatients(p); secureStorage.setItem(LOCAL_KEYS.PATIENTS, p); }
      if (m) { setInventory(m); secureStorage.setItem(LOCAL_KEYS.INVENTORY, m); }
      if (srv) { setClinicalServices(srv); secureStorage.setItem(LOCAL_KEYS.SERVICES, srv); }
      if (a) { setAppointments(a); secureStorage.setItem(LOCAL_KEYS.APPOINTMENTS, a); }
      if (i) { setInvoices(i); secureStorage.setItem(LOCAL_KEYS.INVOICES, i); }
      if (e) { setExpenses(e); secureStorage.setItem(LOCAL_KEYS.EXPENSES, e); }
      if (s) { setSalaries(s); secureStorage.setItem(LOCAL_KEYS.SALARIES, s); }
      if (u) { setUsers(u); secureStorage.setItem(LOCAL_KEYS.USERS, u); }
      if (rx_list) { setPrescriptions(rx_list); secureStorage.setItem(LOCAL_KEYS.PRESCRIPTIONS, rx_list); }
      if (sup_list) { setSuppliers(sup_list); secureStorage.setItem(LOCAL_KEYS.SUPPLIERS, sup_list); }
      if (lab_list) { setLabResults(lab_list); secureStorage.setItem(LOCAL_KEYS.LABS, lab_list); }

      const h = await firebaseService.getInventory(); // Keep as is to avoid breaking if API signature mismatches
      const savedHistory = secureStorage.getItem(LOCAL_KEYS.HISTORY) || [];
      setPatientHistory(savedHistory);
    } catch (error) {
      console.warn("Background sync failed. Using encrypted local data.");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    refreshData();
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Persistence Wrappers using Secure Storage
  const addNewPatient = async (p: Patient) => {
    const updated = [p, ...patients];
    setPatients(updated);
    secureStorage.setItem(LOCAL_KEYS.PATIENTS, updated);
    await firebaseService.insertPatient(p);
  };

  const updatePat = async (id: string, p: Partial<Patient>) => {
    const updated = patients.map(item => item.id === id ? { ...item, ...p } : item);
    setPatients(updated);
    secureStorage.setItem(LOCAL_KEYS.PATIENTS, updated);
    await firebaseService.updatePatient(id, p);
  };

  const deletePat = async (id: string) => {
    const updated = patients.filter(p => p.id !== id);
    setPatients(updated);
    secureStorage.setItem(LOCAL_KEYS.PATIENTS, updated);
    await firebaseService.deletePatient(id);
  };

  const addNewHistory = async (h: PatientHistory) => {
    const updated = [h, ...patientHistory];
    setPatientHistory(updated);
    secureStorage.setItem(LOCAL_KEYS.HISTORY, updated);
    await firebaseService.insertHistory(h);
  };

  const addNewPrescription = async (p: Prescription) => {
    const updated = [p, ...prescriptions];
    setPrescriptions(updated);
    secureStorage.setItem(LOCAL_KEYS.PRESCRIPTIONS, updated);
    await firebaseService.insertPrescription(p);
  };

  const removePrescription = async (id: string) => {
    const updated = prescriptions.filter(p => p.id !== id);
    setPrescriptions(updated);
    secureStorage.setItem(LOCAL_KEYS.PRESCRIPTIONS, updated);
    await firebaseService.deletePrescription(id);
  };

  const addNewLabResult = async (l: LabResult) => {
    const updated = [l, ...labResults];
    setLabResults(updated);
    secureStorage.setItem(LOCAL_KEYS.LABS, updated);
    await firebaseService.insertLabResult(l);
  };

  const addNewMedicine = async (m: Medicine) => {
    const updated = [m, ...inventory];
    setInventory(updated);
    secureStorage.setItem(LOCAL_KEYS.INVENTORY, updated);
    await firebaseService.insertMedicine(m);
  };

  const updateMed = async (id: string, m: Partial<Medicine>) => {
    const updated = inventory.map(item => item.id === id ? { ...item, ...m } : item);
    setInventory(updated);
    secureStorage.setItem(LOCAL_KEYS.INVENTORY, updated);
    await firebaseService.updateMedicine(id, m);
  };

  const deleteMed = async (id: string) => {
    const updated = inventory.filter(m => m.id !== id);
    setInventory(updated);
    secureStorage.setItem(LOCAL_KEYS.INVENTORY, updated);
    await firebaseService.deleteMedicine(id);
  };

  const addNewService = async (s: ClinicalService) => {
    const updated = [s, ...clinicalServices];
    setClinicalServices(updated);
    secureStorage.setItem(LOCAL_KEYS.SERVICES, updated);
    await firebaseService.insertService(s);
  };

  const removeService = async (id: string) => {
    const updated = clinicalServices.filter(s => s.id !== id);
    setClinicalServices(updated);
    secureStorage.setItem(LOCAL_KEYS.SERVICES, updated);
    await firebaseService.deleteService(id);
  };

  const addNewSupplier = async (s: Supplier) => {
    const updated = [s, ...suppliers];
    setSuppliers(updated);
    secureStorage.setItem(LOCAL_KEYS.SUPPLIERS, updated);
    await firebaseService.insertSupplier(s);
  };

  const updateSupplier = async (id: string, updates: Partial<Supplier>) => {
    const updated = suppliers.map(s => s.id === id ? { ...s, ...updates } : s);
    setSuppliers(updated);
    secureStorage.setItem(LOCAL_KEYS.SUPPLIERS, updated);
    await firebaseService.updateSupplier(id, updates);
  };

  const addTransaction = async (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => {
    // 1. Update Invoices
    const updatedInvoices = [inv, ...invoices];
    setInvoices(updatedInvoices);
    secureStorage.setItem(LOCAL_KEYS.INVOICES, updatedInvoices);

    // 2. Update Inventory Local
    if (items && items.length > 0) {
      const itemMap = new Map(items.map(i => [i.id, i.quantity]));
      const updatedInventory = inventory.map(prod => {
        const qty = itemMap.get(prod.id);
        if (qty) return { ...prod, stock: Math.max(0, prod.stock - qty) };
        return prod;
      });
      setInventory(updatedInventory);
      secureStorage.setItem(LOCAL_KEYS.INVENTORY, updatedInventory);
    }

    // 3. Remote Sync
    return await firebaseService.createTransaction(inv, items);
  };

  const updateInvoiceStatus = async (id: string, status: 'Paid' | 'Pending' | 'Partial' | 'Refunded', isRefund?: boolean) => {
    const updates: Partial<Invoice> = { status };
    if (isRefund !== undefined) updates.isRefund = isRefund;

    const updatedInvoices = invoices.map(inv => inv.id === id ? { ...inv, ...updates } : inv);
    setInvoices(updatedInvoices);
    secureStorage.setItem(LOCAL_KEYS.INVOICES, updatedInvoices);

    await firebaseService.updateInvoice(id, updates);
  };

  const addNewAppointment = async (a: Appointment) => {
    const updated = [a, ...appointments];
    setAppointments(updated);
    secureStorage.setItem(LOCAL_KEYS.APPOINTMENTS, updated);
    await firebaseService.insertAppointment(a);
  };

  const addExpense = async (e: Expense) => {
    const updated = [e, ...expenses];
    setExpenses(updated);
    secureStorage.setItem(LOCAL_KEYS.EXPENSES, updated);
    await firebaseService.insertExpense(e);
  };

  const addSalary = async (s: Salary) => {
    const updated = [s, ...salaries];
    setSalaries(updated);
    secureStorage.setItem(LOCAL_KEYS.SALARIES, updated);
    await firebaseService.insertSalary(s);
  };

  const addNewUser = async (u: StaffUser) => {
    const res = await firebaseService.insertUser(u);
    if (res) {
      const updated = [u, ...users];
      setUsers(updated);
      secureStorage.setItem(LOCAL_KEYS.USERS, updated);
    }
    return { success: !!res };
  };

  const removeUser = async (id: string) => {
    const updated = users.filter(u => u.id !== id);
    setUsers(updated);
    secureStorage.setItem(LOCAL_KEYS.USERS, updated);
    await firebaseService.deleteUser(id);
  };

  const updateUserProfile = async (id: string, data: Partial<StaffUser>) => {
    const res = await firebaseService.updateUser(id, data);
    if (res) {
      const updated = users.map(u => u.id === id ? { ...u, ...data } : u);
      setUsers(updated);
      secureStorage.setItem(LOCAL_KEYS.USERS, updated);
    }
    return res;
  };

  return (
    <DataContext.Provider value={{
      patients, inventory, clinicalServices, appointments, invoices, expenses, salaries, users, patientHistory, prescriptions, suppliers, labResults,
      refreshData, addNewPatient, updatePat, deletePat, addNewHistory, addNewPrescription, removePrescription, addNewLabResult, addNewMedicine, updateMed, deleteMed, 
      addNewService, removeService, addNewSupplier, updateSupplier, addTransaction, updateInvoiceStatus, addNewAppointment, addExpense, addSalary,
      addNewUser, removeUser, updateUserProfile, isLoading, isOnline
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error('useData must be used within DataProvider');
  return context;
};

