    const updatedTeeth = { ...selectedPatient.teethStatus, [toothNumber]: newStatus };

    // Optimistic Update
    setSelectedPatient({ ...selectedPatient, teethStatus: updatedTeeth });

    // Save to DB
    await updatePat(selectedPatient.id, { teethStatus: updatedTeeth });
  };

